using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string? dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateWithData(string? dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        private static void SeedData(SchoolContext context)
        {
            var dept1 = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 100000m,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = null
            };
            var dept2 = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 75000m,
                StartDate = new DateTime(2019, 9, 1),
                InstructorID = null
            };

            context.Departments.AddRange(dept1, dept2);

            var instructor1 = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = new DateTime(2015, 3, 15),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { InstructorID = 1, Location = "Room 101" }
            };
            var instructor2 = new Instructor
            {
                ID = 2,
                LastName = "Johnson",
                FirstMidName = "Jane",
                HireDate = new DateTime(2018, 8, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            context.Instructors.AddRange(instructor1, instructor2);

            var course1 = new Course
            {
                CourseID = 101,
                Title = "Intro to CS",
                Credits = 3,
                DepartmentID = 1,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            var course2 = new Course
            {
                CourseID = 201,
                Title = "Calculus",
                Credits = 4,
                DepartmentID = 2,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            context.Courses.AddRange(course1, course2);

            var student1 = new Student
            {
                ID = 10,
                LastName = "Doe",
                FirstMidName = "Alice",
                EnrollmentDate = new DateTime(2022, 9, 1),
                Enrollments = new List<Enrollment>()
            };
            var student2 = new Student
            {
                ID = 11,
                LastName = "Brown",
                FirstMidName = "Bob",
                EnrollmentDate = new DateTime(2023, 1, 15),
                Enrollments = new List<Enrollment>()
            };
            var student3 = new Student
            {
                ID = 12,
                LastName = "Adams",
                FirstMidName = "Charlie",
                EnrollmentDate = new DateTime(2021, 6, 1),
                Enrollments = new List<Enrollment>()
            };

            context.Students.AddRange(student1, student2, student3);

            var enrollment1 = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 101,
                StudentID = 10,
                Grade = Grade.A
            };
            var enrollment2 = new Enrollment
            {
                EnrollmentID = 2,
                CourseID = 201,
                StudentID = 11,
                Grade = Grade.B
            };

            context.Enrollments.AddRange(enrollment1, enrollment2);

            var ca1 = new CourseAssignment { InstructorID = 1, CourseID = 101 };
            context.CourseAssignments.Add(ca1);

            context.SaveChanges();

            // Update department administrators after instructors are saved
            dept1.InstructorID = 1;
            context.SaveChanges();
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _sut;

        public NotificationServiceTests()
        {
            _sut = new NotificationService();
            // Drain any leftover notifications from other tests (static queue)
            while (_sut.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _sut.Dispose();
        }

        [Fact]
        public void SendNotification_WithDisplayName_CreatesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Student", "1", "Alice Doe", EntityOperation.CREATE, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("Alice Doe", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            // Act
            _sut.SendNotification("Course", "42", EntityOperation.UPDATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
            Assert.Contains("updated", notification.Message);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "created")]
        [InlineData(EntityOperation.UPDATE, "updated")]
        [InlineData(EntityOperation.DELETE, "deleted")]
        public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedVerb)
        {
            // Act
            _sut.SendNotification("Department", "5", "Engineering", operation, "TestUser");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains(expectedVerb, notification.Message);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.Null(result);
        }

        [Fact]
        public void SendNotification_MultipleMessages_ReceivedInOrder()
        {
            // Arrange & Act
            _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            _sut.SendNotification("Course", "2", "Second", EntityOperation.UPDATE);
            _sut.SendNotification("Department", "3", "Third", EntityOperation.DELETE);

            // Assert
            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();
            var third = _sut.ReceiveNotification();

            Assert.Equal("Student", first!.EntityType);
            Assert.Equal("Course", second!.EntityType);
            Assert.Equal("Department", third!.EntityType);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToNow()
        {
            // Arrange
            var before = DateTime.Now.AddSeconds(-1);

            // Act
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.True(notification.CreatedAt >= before);
            Assert.True(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory, but should not throw
            var exception = Record.Exception(() => _sut.MarkAsRead(999));
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }
    }
}

using Xunit;
using System.Linq;

namespace ContosoUniversity.Tests.Helpers
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(1, result[0]);
            Assert.Equal(10, result[9]);
        }

        [Fact]
        public void Create_MiddlePage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.Equal(10, result.Count);
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(11, result[0]);
            Assert.Equal(20, result[9]);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 10);

            // Assert
            Assert.Equal(5, result.Count);
            Assert.Equal(3, result.PageIndex);
            Assert.Equal(21, result[0]);
            Assert.Equal(25, result[4]);
        }

        [Fact]
        public void HasPreviousPage_OnFirstPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_OnSecondPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_OnLastPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_OnFirstPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_SinglePage_NoNavigationNeeded()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly_WithExactDivision()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void TotalPages_RoundsUp_WithRemainder()
        {
            var source = Enumerable.Range(1, 31).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(4, result.TotalPages);
        }
    }
}

