                LastName = "Johnson",
                FirstMidName = "Jane",
                HireDate = new DateTime(2018, 8, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            context.Instructors.AddRange(instructor1, instructor2);

            var course1 = new Course
            {
                CourseID = 101,
                Title = "Intro to CS",
                Credits = 3,
                DepartmentID = 1,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            var course2 = new Course
            {
                CourseID = 201,
                Title = "Calculus",
                Credits = 4,
                DepartmentID = 2,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            context.Courses.AddRange(course1, course2);

            var student1 = new Student
            {
                ID = 10,
                LastName = "Doe",
                FirstMidName = "Alice",
                EnrollmentDate = new DateTime(2022, 9, 1),
                Enrollments = new List<Enrollment>()
            };
            var student2 = new Student
            {
                ID = 11,
                LastName = "Brown",
                FirstMidName = "Bob",
                EnrollmentDate = new DateTime(2023, 1, 15),
                Enrollments = new List<Enrollment>()
            };
            var student3 = new Student
            {
                ID = 12,
                LastName = "Adams",
                FirstMidName = "Charlie",
                EnrollmentDate = new DateTime(2021, 6, 1),
                Enrollments = new List<Enrollment>()
            };

            context.Students.AddRange(student1, student2, student3);

            var enrollment1 = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 101,
                StudentID = 10,
                Grade = Grade.A
            };
            var enrollment2 = new Enrollment
            {
                EnrollmentID = 2,
                CourseID = 201,
                StudentID = 11,
                Grade = Grade.B
            };

            context.Enrollments.AddRange(enrollment1, enrollment2);

            var ca1 = new CourseAssignment { InstructorID = 1, CourseID = 101 };
            context.CourseAssignments.Add(ca1);

            context.SaveChanges();

            // Update department administrators after instructors are saved
            dept1.InstructorID = 1;
            context.SaveChanges();
        }
    }
}

