using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithData();
            _controller = new StudentsController(_context);
            SetupController(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SetupController(Controller controller)
        {
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            controller.TempData = new TempDataDictionary(
                controller.ControllerContext.HttpContext,
                new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        [Fact]
        public void Index_NoParameters_ReturnsViewWithAllStudentsSortedByLastName()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
            // Default sort is by LastName ascending
            Assert.Equal("Adams", model[0].LastName);
            Assert.Equal("Brown", model[1].LastName);
            Assert.Equal("Doe", model[2].LastName);
        }

        [Fact]
        public void Index_SortByNameDesc_ReturnsStudentsSortedDescending()
        {
            // Act
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Doe", model[0].LastName);
            Assert.Equal("Brown", model[1].LastName);
            Assert.Equal("Adams", model[2].LastName);
        }

        [Fact]
        public void Index_SortByDate_ReturnsStudentsSortedByEnrollmentDateAsc()
        {
            // Act
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Adams", model[0].LastName); // 2021
            Assert.Equal("Doe", model[1].LastName);   // 2022
            Assert.Equal("Brown", model[2].LastName); // 2023
        }

        [Fact]
        public void Index_SortByDateDesc_ReturnsStudentsSortedByEnrollmentDateDesc()
        {
            // Act
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Brown", model[0].LastName); // 2023
            Assert.Equal("Doe", model[1].LastName);   // 2022
            Assert.Equal("Adams", model[2].LastName); // 2021
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            // Act
            var result = _controller.Index(null, null, "Doe", null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Doe", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            // Act
            var result = _controller.Index(null, null, "Bob", null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Brown", model[0].LastName);
        }

        [Fact]
        public void Index_SearchStringResetsPage()
        {
            // When searchString is provided, page should be reset to 1
            var result = _controller.Index(null, null, "Doe", 3) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_CurrentFilterUsedWhenNoSearchString()
        {
            // Act
            var result = _controller.Index(null, "Doe", null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Details_ValidId_ReturnsStudentWithEnrollments()
        {
            // Act
            var result = _controller.Details(10) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Doe", student.LastName);
            Assert.Equal("Alice", student.FirstMidName);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithStudentAndTodaysDate()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2024, 1, 1)
            };

            // Act
            var result = _controller.Create(student);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(4, _context.Students.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2024, 1, 1)
            };
            _controller.ModelState.AddModelError("LastName", "Required");

            // Act
            var result = _controller.Create(student);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(student, viewResult.Model);
        }

        [Fact]
        public void Create_Post_DefaultEnrollmentDate_AddsModelError()
        {
            // Arrange
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            // Act
            var result = _controller.Create(student);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_DateOutOfRange_AddsModelError()
        {
            // Arrange
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            // Act
            var result = _controller.Create(student);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            // Act
            var result = _controller.Edit(10) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Doe", student.LastName);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Edit(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = _context.Students.First();
            student.LastName = "Updated";

            // Detach to simulate form post
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            // Act
            var result = _controller.Edit(student);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var student = new Student
            {
                ID = 10,
                LastName = "Doe",
                FirstMidName = "Alice",
                EnrollmentDate = new DateTime(2022, 9, 1)
            };
            _controller.ModelState.AddModelError("LastName", "Required");

            // Act
            var result = _controller.Edit(student);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(student, viewResult.Model);
        }

        [Fact]
        public void Edit_Post_DefaultEnrollmentDate_AddsModelError()
        {
            // Arrange
            var student = new Student
            {
                ID = 10,
                LastName = "Doe",
                FirstMidName = "Alice",
                EnrollmentDate = default
            };

            // Act
            var result = _controller.Edit(student);

            // Assert
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            // Act
            var result = _controller.Delete(10) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Doe", student.LastName);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Delete(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
        {
            // Act
            var result = _controller.DeleteConfirmed(10);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(2, _context.Students.Count());
        }

        [Fact]
        public void Index_SetsViewBagCurrentSort()
        {
            // Act
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            Assert.Equal("name_desc", _controller.ViewBag.CurrentSort);
        }

        [Fact]
        public void Index_SetsViewBagSortParameters()
        {
            // Act - default sort
            _controller.Index(null, null, null, null);

            // Assert
            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_DateSort_SetsDateSortParmToDesc()
        {
            // Act
            _controller.Index("Date", null, null, null);

            // Assert
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }
    }
}

