using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithData();
            _controller = new StudentsController(_context);
            SetupController(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SetupController(Controller controller)
        {
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            controller.TempData = new TempDataDictionary(
                controller.ControllerContext.HttpContext,
                new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        [Fact]
        public void Index_NoParameters_ReturnsViewWithAllStudentsSortedByLastName()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
            // Default sort is by LastName ascending
            Assert.Equal("Adams", model[0].LastName);
            Assert.Equal("Brown", model[1].LastName);
            Assert.Equal("Doe", model[2].LastName);
        }

        [Fact]
        public void Index_SortByNameDesc_ReturnsStudentsSortedDescending()
        {
            // Act
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Doe", model[0].LastName);
            Assert.Equal("Brown", model[1].LastName);
            Assert.Equal("Adams", model[2].LastName);
        }

        [Fact]
        public void Index_SortByDate_ReturnsStudentsSortedByEnrollmentDateAsc()
        {
            // Act
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Adams", model[0].LastName); // 2021
            Assert.Equal("Doe", model[1].LastName);   // 2022
            Assert.Equal("Brown", model[2].LastName); // 2023
        }

        [Fact]
        public void Index_SortByDateDesc_ReturnsStudentsSortedByEnrollmentDateDesc()
        {
            // Act
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Brown", model[0].LastName); // 2023
            Assert.Equal("Doe", model[1].LastName);   // 2022
            Assert.Equal("Adams", model[2].LastName); // 2021
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            // Act
            var result = _controller.Index(null, null, "Doe", null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Doe", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            // Act
            var result = _controller.Index(null, null, "Bob", null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Brown", model[0].LastName);
        }

        [Fact]
        public void Index_SearchStringResetsPage()
        {
            // When searchString is provided, page should be reset to 1
            var result = _controller.Index(null, null, "Doe", 3) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_CurrentFilterUsedWhenNoSearchString()
