using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _envMock;
        private readonly Mock<ILogger<CoursesController>> _loggerMock;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateWithData();
            _envMock = new Mock<IWebHostEnvironment>();
            _loggerMock = new Mock<ILogger<CoursesController>>();

            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
            _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
            SetupController(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
            {
                Directory.Delete(_tempDir, true);
            }
        }

        private static void SetupController(Controller controller)
        {
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            controller.TempData = new TempDataDictionary(
                controller.ControllerContext.HttpContext,
                new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            // Act
            var result = _controller.Details(101) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Intro to CS", course.Title);
            Assert.Equal(3, course.Credits);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            // Arrange
            var course = new Course
            {
                CourseID = 301,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            // Act
            var result = _controller.Create(course, null!);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(3, _context.Courses.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var course = new Course { CourseID = 301, Title = "Test", Credits = 3, DepartmentID = 1 };
            _controller.ModelState.AddModelError("Title", "Required");

            // Act
            var result = _controller.Create(course, null!);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(course, viewResult.Model);
        }

        [Fact]
        public void Create_Post_WithValidImage_SavesFileAndRedirects()
        {
            // Arrange
            var course = new Course { CourseID = 302, Title = "Image Course", Credits = 2, DepartmentID = 1 };
            var fileMock = CreateMockFormFile("test.jpg", 1024);

            // Act
            var result = _controller.Create(course, fileMock.Object);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.NotNull(course.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_WithInvalidFileExtension_ReturnsViewWithError()
        {
            // Arrange
            var course = new Course { CourseID = 303, Title = "Bad File", Credits = 2, DepartmentID = 1 };
            var fileMock = CreateMockFormFile("test.exe", 1024);

            // Act
            var result = _controller.Create(course, fileMock.Object);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_WithOversizedFile_ReturnsViewWithError()
        {
            // Arrange
            var course = new Course { CourseID = 304, Title = "Big File", Credits = 2, DepartmentID = 1 };
            var fileMock = CreateMockFormFile("test.jpg", 6 * 1024 * 1024); // 6MB

            // Act
            var result = _controller.Create(course, fileMock.Object);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            // Act
            var result = _controller.Edit(101) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Intro to CS", course.Title);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Edit(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            // Arrange
            var course = _context.Courses.First();
            course.Title = "Updated Title";
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            // Act
            var result = _controller.Edit(course, null!);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var course = new Course { CourseID = 101, Title = "Test", Credits = 3, DepartmentID = 1 };
            _controller.ModelState.AddModelError("Title", "Required");

            // Act
            var result = _controller.Edit(course, null!);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(course, viewResult.Model);
        }

        [Fact]
        public void Edit_Post_WithInvalidExtension_ReturnsViewWithError()
        {
            // Arrange
            var course = new Course { CourseID = 101, Title = "Intro to CS", Credits = 3, DepartmentID = 1 };
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            var fileMock = CreateMockFormFile("malware.txt", 1024);

            // Act
            var result = _controller.Edit(course, fileMock.Object);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            // Act
            var result = _controller.Delete(101) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Intro to CS", course.Title);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            // Act
            var result = _controller.DeleteConfirmed(101);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Single(_context.Courses);
        }

        [Theory]
        [InlineData(".jpg")]
        [InlineData(".jpeg")]
        [InlineData(".png")]
        [InlineData(".gif")]
        [InlineData(".bmp")]
        public void Create_Post_AllowedImageExtensions_AcceptsFile(string extension)
        {
            // Arrange
            var course = new Course { CourseID = 400 + extension.GetHashCode() % 100, Title = $"Course {extension}", Credits = 1, DepartmentID = 1 };
            var fileMock = CreateMockFormFile($"image{extension}", 1024);

            // Act
            var result = _controller.Create(course, fileMock.Object);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        private static Mock<IFormFile> CreateMockFormFile(string fileName, long length)
        {
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => { });
            return fileMock;
        }
    }
}

