using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithData();
            _controller = new DepartmentsController(_context);
            SetupController(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SetupController(Controller controller)
        {
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            controller.TempData = new TempDataDictionary(
                controller.ControllerContext.HttpContext,
                new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        [Fact]
        public void Index_ReturnsViewWithAllDepartments()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            // Act
            var result = _controller.Details(1) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("Engineering", department.Name);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Details(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithInstructorSelectList()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            // Arrange
            var department = new Department
            {
                Name = "Physics",
                Budget = 50000m,
                StartDate = new DateTime(2024, 1, 1),
                InstructorID = 1
            };

            // Act
            var result = _controller.Create(department);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(3, _context.Departments.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var department = new Department
            {
                Name = "Test",
                Budget = 1000m,
                StartDate = new DateTime(2024, 1, 1)
            };
            _controller.ModelState.AddModelError("Name", "Required");

            // Act
            var result = _controller.Create(department);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(department, viewResult.Model);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            // Act
            var result = _controller.Edit(1) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("Engineering", department.Name);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Edit(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            // Arrange
            var department = _context.Departments.First();
            department.Name = "Updated Engineering";
            _context.Entry(department).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            // Act
            var result = _controller.Edit(department);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var department = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 100000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            _controller.ModelState.AddModelError("Name", "Required");

            // Act
            var result = _controller.Edit(department);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(department, viewResult.Model);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithDepartment()
        {
            // Act
            var result = _controller.Delete(1) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("Engineering", department.Name);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Delete(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesDepartmentAndRedirects()
        {
            // Act
            var result = _controller.DeleteConfirmed(2);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Single(_context.Departments);
        }
    }
}

