using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithData();
            _controller = new InstructorsController(_context);
            SetupController(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SetupController(Controller controller)
        {
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            controller.TempData = new TempDataDictionary(
                controller.ControllerContext.HttpContext,
                new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        [Fact]
        public void Index_NoParameters_ReturnsViewWithAllInstructors()
        {
            // Act
            var result = _controller.Index(null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            // Act
            var result = _controller.Index(1, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses); // Instructor 1 teaches course 101
        }

        [Fact]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            // Act
            var result = _controller.Index(1, 101) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            // Act
            var result = _controller.Details(1) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Smith", instructor.LastName);
            Assert.Equal("John", instructor.FirstMidName);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Details(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithInstructorAndAssignedCourses()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(instructor.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_Post_ValidInstructor_NoCourses_RedirectsToIndex()
        {
            // Arrange
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2024, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            // Act
            var result = _controller.Create(instructor, null!);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(3, _context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_ValidInstructor_WithCourses_AddsCourseAssignments()
        {
            // Arrange
            var instructor = new Instructor
            {
                LastName = "CourseInstructor",
                FirstMidName = "With",
                HireDate = new DateTime(2024, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            var selectedCourses = new[] { "101", "201" };

            // Act
            var result = _controller.Create(instructor, selectedCourses);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var instructor = new Instructor
            {
                LastName = "Test",
                FirstMidName = "Instructor",
                HireDate = new DateTime(2024, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            _controller.ModelState.AddModelError("LastName", "Required");

            // Act
            var result = _controller.Create(instructor, null!);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(instructor, viewResult.Model);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            // Act
            var result = _controller.Edit(1) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Smith", instructor.LastName);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit((int?)null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            // Act
            var result = _controller.Delete(1) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Smith", instructor.LastName);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Delete(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndClearsDepartmentAdmin()
        {
            // The instructor with ID=1 is the admin of department 1
            // Act
            var result = _controller.DeleteConfirmed(1);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Single(_context.Instructors);

            // Verify department admin was cleared
            var dept = _context.Departments.Find(1);
            Assert.Null(dept!.InstructorID);
        }

        [Fact]
        public void DeleteConfirmed_InstructorWithNoAdminDept_RemovesInstructor()
        {
            // Instructor 2 is not an admin of any department
            // Act
            var result = _controller.DeleteConfirmed(2);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Single(_context.Instructors);
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            // Act
            var result = _controller.Index(null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            var instructors = model.Instructors.ToList();
            Assert.Equal("Johnson", instructors[0].LastName);
            Assert.Equal("Smith", instructors[1].LastName);
        }
    }
}

