using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextFactory.CreateWithData();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void Students_CanBeQueried()
        {
            var students = _context.Students.ToList();
            Assert.Equal(3, students.Count);
        }

        [Fact]
        public void Courses_CanBeQueried()
        {
            var courses = _context.Courses.ToList();
            Assert.Equal(2, courses.Count);
        }

        [Fact]
        public void Departments_CanBeQueried()
        {
            var departments = _context.Departments.ToList();
            Assert.Equal(2, departments.Count);
        }

        [Fact]
        public void Instructors_CanBeQueried()
        {
            var instructors = _context.Instructors.ToList();
            Assert.Equal(2, instructors.Count);
        }

        [Fact]
        public void Enrollments_CanBeQueried()
        {
            var enrollments = _context.Enrollments.ToList();
            Assert.Equal(2, enrollments.Count);
        }

        [Fact]
        public void CourseAssignments_HaveCompositeKey()
        {
            var ca = _context.CourseAssignments.First();
            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(101, ca.CourseID);
        }

        [Fact]
        public void Student_Enrollment_NavigationLoads()
        {
            var student = _context.Students
                .Include(s => s.Enrollments)
                .First(s => s.ID == 10);

            Assert.NotNull(student.Enrollments);
            Assert.Single(student.Enrollments);
            Assert.Equal(Grade.A, student.Enrollments.First().Grade);
        }

        [Fact]
        public void Course_Department_NavigationLoads()
        {
            var course = _context.Courses
                .Include(c => c.Department)
                .First(c => c.CourseID == 101);

            Assert.NotNull(course.Department);
            Assert.Equal("Engineering", course.Department.Name);
        }

        [Fact]
        public void Instructor_OfficeAssignment_NavigationLoads()
        {
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.ID == 1);

            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal("Room 101", instructor.OfficeAssignment.Location);
        }

        [Fact]
        public void Instructor_CourseAssignments_NavigationLoads()
        {
            var instructor = _context.Instructors
                .Include(i => i.CourseAssignments)
                .First(i => i.ID == 1);

            Assert.NotNull(instructor.CourseAssignments);
            Assert.Single(instructor.CourseAssignments);
        }

        [Fact]
        public void AddStudent_PersistsToDatabase()
        {
            // Arrange
            var student = new Student
            {
                LastName = "New",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2024, 6, 1),
                Enrollments = new List<Enrollment>()
            };

            // Act
            _context.Students.Add(student);
            _context.SaveChanges();

            // Assert
            Assert.Equal(4, _context.Students.Count());
            var saved = _context.Students.First(s => s.LastName == "New");
            Assert.Equal("Student", saved.FirstMidName);
        }

        [Fact]
        public void DeleteStudent_RemovesFromDatabase()
        {
            // Arrange
            var student = _context.Students.First(s => s.ID == 12);

            // Act
            _context.Students.Remove(student);
            _context.SaveChanges();

            // Assert
            Assert.Equal(2, _context.Students.Count());
            Assert.Null(_context.Students.Find(12));
        }

        [Fact]
        public void UpdateCourse_PersistsChanges()
        {
            // Arrange
            var course = _context.Courses.First(c => c.CourseID == 101);

            // Act
            course.Title = "Advanced CS";
            _context.SaveChanges();

            // Assert
            var updated = _context.Courses.Find(101);
            Assert.Equal("Advanced CS", updated!.Title);
        }

        [Fact]
        public void Department_Administrator_NavigationLoads()
        {
            var department = _context.Departments
                .Include(d => d.Administrator)
                .First(d => d.DepartmentID == 1);

            Assert.NotNull(department.Administrator);
            Assert.Equal("Smith", department.Administrator.LastName);
        }

        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirstName()
        {
            var student = _context.Students.First(s => s.ID == 10);
            Assert.Equal("Doe, Alice", student.FullName);
        }
    }
}

