using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_EmptyDatabase_SeedsAllData()
        {
            // Arrange
            var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.Equal(8, context.Students.Count());
            Assert.Equal(5, context.Instructors.Count());
            Assert.Equal(4, context.Departments.Count());
            Assert.Equal(7, context.Courses.Count());
            Assert.Equal(3, context.OfficeAssignments.Count());
            Assert.True(context.CourseAssignments.Count() >= 8);
            Assert.True(context.Enrollments.Count() >= 11);

            context.Dispose();
        }

        [Fact]
        public void Initialize_AlreadySeededDatabase_DoesNotDuplicate()
        {
            // Arrange
            var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);
            var studentCount = context.Students.Count();

            // Act - Initialize again
            DbInitializer.Initialize(context);

            // Assert - counts should be the same
            Assert.Equal(studentCount, context.Students.Count());

            context.Dispose();
        }

        [Fact]
        public void Initialize_SetsCorrectDepartmentAdministrators()
        {
            // Arrange
            var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            var english = context.Departments.Include(d => d.Administrator)
                .Single(d => d.Name == "English");
            Assert.Equal("Abercrombie", english.Administrator!.LastName);

            var math = context.Departments.Include(d => d.Administrator)
                .Single(d => d.Name == "Mathematics");
            Assert.Equal("Fakhouri", math.Administrator!.LastName);

            context.Dispose();
        }

        [Fact]
        public void Initialize_CreatesOfficeAssignments()
        {
            // Arrange
            var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            var fakhouri = context.Instructors
                .Include(i => i.OfficeAssignment)
                .Single(i => i.LastName == "Fakhouri");
            Assert.Equal("Smith 17", fakhouri.OfficeAssignment!.Location);

            context.Dispose();
        }

        [Fact]
        public void Initialize_CreatesCourseAssignments()
        {
            // Arrange
            var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            var chemistry = context.Courses
                .Include(c => c.CourseAssignments)
                .Single(c => c.Title == "Chemistry");
            Assert.Equal(2, chemistry.CourseAssignments.Count);

            context.Dispose();
        }

        [Fact]
        public void Initialize_CreatesEnrollmentsWithGrades()
        {
            // Arrange
            var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            var alexander = context.Students
                .Include(s => s.Enrollments)
                .Single(s => s.LastName == "Alexander");
            Assert.Equal(3, alexander.Enrollments.Count);
            Assert.Contains(alexander.Enrollments, e => e.Grade == Grade.A);

            context.Dispose();
        }

        [Fact]
        public void Initialize_SomeEnrollmentsHaveNoGrade()
        {
            // Arrange
            var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert - Anand's Chemistry enrollment has no grade
            var anand = context.Students
                .Include(s => s.Enrollments)
                .Single(s => s.LastName == "Anand");
            Assert.Contains(anand.Enrollments, e => e.Grade == null);

            context.Dispose();
        }
    }
}

