[Fact]
public void DeleteConfirmed_CourseWithImage_DeletesImageFile()
{
    // Arrange - give a course an image path
    var course = _context.Courses.First(c => c.CourseID == 101);
    var imgDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
    Directory.CreateDirectory(imgDir);
    var imgPath = Path.Combine(imgDir, "test_img.jpg");
    File.WriteAllBytes(imgPath, new byte[] { 0xFF, 0xD8 });
    course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_img.jpg";
    _context.SaveChanges();

    // Act
    var result = _controller.DeleteConfirmed(101);

    // Assert
    Assert.IsType<RedirectToActionResult>(result);
    Assert.False(File.Exists(imgPath));
}

