[Fact]
public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
{
    // Drain any existing notifications first
    JsonResult drain;
    do { drain = _controller.GetNotifications(); } while (false);

    // Act - call again to get clean state
    var result = _controller.GetNotifications();

    // Assert
    Assert.NotNull(result);
